// +esm 的 luma.gl 传递依赖混入不同 patch；使用 deck.gl 官方自包含 browser bundle 保持单一运行时
const el = document.getElementById('deck'); el.style.cssText = 'height:500px;position:relative'; el.textContent = 'Loading WebGL view…';
const previousDeck = globalThis.deck; await new Promise((ok, bad) => { const s = document.createElement('script'); s.src = 'https://cdn.jsdelivr.net/npm/deck.gl@9.3.7/dist.min.js'; s.onload = () => { s.remove(); ok(); }; s.onerror = () => bad(new Error('failed to load deck.gl browser bundle')); el.appendChild(s); });
const { Deck, ScatterplotLayer } = globalThis.deck; if (previousDeck === undefined) delete globalThis.deck; else globalThis.deck = previousDeck; el.textContent = '';
const deck = new Deck({ parent: el, initialViewState: data.initialViewState, controller: true, layers: [ new ScatterplotLayer({ id:'pts', data: data.points, getPosition: d=>d.position, getRadius: d=>d.radius ?? 100, getFillColor: d=>d.color ?? [255,140,0] }) ] });

